var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으음…….","JPN":"ううん……","ENG":"Mmm...","TWN":"嗯……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흐아암……. 겨우 잠들었는데, 무슨…….","JPN":"ふわぁ……やっと眠ったのに、何……","ENG":"Yawn... I was almost asleep too, what’s...","TWN":"呼哈……我好不容易才睡著的，現在是怎……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아아아아아악!!","JPN":"ああああああっ！！","ENG":"Ahhhhhhhhh!!","TWN":"啊啊啊啊！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이 비명 소리는…… 레버넌트 씨네 어머니?","JPN":"この悲鳴は……レヴナントさんのお母さん？","ENG":"This screaming... Is it Revenant’s mom?","TWN":"這聲音是……亡靈小姐的媽媽？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아, 다리 좀 잡아 줘!","JPN":"レア、足押さえて！","ENG":"Leah, grab her legs!","TWN":"蕾亞，你幫我把腳抓好！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"잡고 있어! 잡고 있다고! 정신 좀 차려, 엄마!!","JPN":"押さえてる！　押さえてるよ！　しっかりして、お母さん！！","ENG":"I’m here! I’m right here! It’s okay, Mom!!","TWN":"有！我抓著呢！媽！你清醒一點！！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"누가 우리 애 좀 살려 주세요……! 우리 애, 우리 애 조옴……!","JPN":"誰か私の娘を助けてください……！　私の、私の娘をぉ……！","ENG":"Somebody save my child...! My baby, my poor baby...!","TWN":"誰來救救我的孩子……！我的孩子，快救……！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"어떡해, 피가 멈추지 않아……! 레아야? 레아야!! 눈 좀 떠! 눈 좀 떠 봐, 제발!!","JPN":"どうしよう、血が止まらない……！　レア？　レア！！　目を覚まして！　頼むから目を開けて！！","ENG":"Oh no, it doesn't stop bleeding...! Leah? Leah!! Open your eyes! Open your eyes, please!!","TWN":"怎麼辦？血一直流……！蕾亞？蕾亞！！你快醒醒！睜開眼睛！媽拜託你！！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마, 나 여기 있어! 여기 있으니까 제발……!","JPN":"お母さん、私はここにいるよ！　ここにいるから……！","ENG":"Mom, I’m right here! I’m here so please...!","TWN":"媽，我在這裡！我就在你身邊，拜託你清醒一點……！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아아아악!! 여보!! 여보오!!","JPN":"ああああ！！　あなた！！　あなたぁ！！","ENG":"Aaaah! Honey! Honey!!","TWN":"啊啊啊啊！！老公！老公！！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사! 왜 나와 있어! 구경해서 좋을 거 없으니까 어서 방에 들어가!","JPN":"軍曹！　なんで出てきたの！　見てて何もいいことなんてないから早く部屋に戻って！","ENG":"Sergeant! Why are you here? No need to be here, just go back to your room!","TWN":"中士！你出來幹嘛！沒什麼好看熱鬧的，快進房間去！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 으…… 네!!","JPN":"あ、う……はい！！","ENG":"Ah, uh... Yes ma’am!!!","TWN":"喔……是！！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"여사님의 비명은 좀처럼 그치지 않았어요.","JPN":"おばさんの悲鳴は止む気配がなかった。","ENG":"But Louise’s screams didn’t stop.","TWN":"她媽媽的哭吼聲還沒停。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 상상 친구 씨. 목을 긁는 절규보다 듣기 싫었던 건…….","JPN":"でもエア友さん。喉を裂くような悲鳴より聞くに堪えなかったのは……","ENG":"However, Mr. Imaginary Friend, what I hated hearing even more than the screaming...","TWN":"不過我想像中的朋友，比起哭吼聲，我更討厭……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"벽에, 그리고 창문에 스멀스멀 스며드는 이웃 주민들의 푸념이었어요.","JPN":"壁、そして窓からぼそぼそともれ聞こえる周辺住民の愚痴だった。","ENG":"Were the complaints of the neighbors coming from outside.","TWN":"從牆壁和窗戶滲入鄰居抱怨聲。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>그냥 내다 버릴 것이지.</color>","JPN":"<color=#ffd34c>もう、捨てちゃえばいいのに。</color>","ENG":"<color=#ffd34c>Just throw her out.</color>","TWN":"<color=#ffd34c>乾脆扔掉吧！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>또 저러네, 또.</color>","JPN":"<color=#ffd34c>また始まったよ、また。</color>","ENG":"<color=#ffd34c>Poor thing, it’s happening again.</color>","TWN":"<color=#ffd34c>你又來！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>딱해도 하루 이틀이지 원…….</color>","JPN":"<color=#ffd34c>最初は気の毒に思ったけれど、まったく……</color>","ENG":"<color=#ffd34c>I feel sorry for her but, this is too much...</color>","TWN":"<color=#ffd34c>反正丟臉又不是這一兩天的事……</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"연민으로 토핑한 불평이라는 게 오랜만에 들으니 진짜 거북하더라고요.","JPN":"憐れみでトッピングされた不満というものを久々に聞いたら、本当に居心地が悪くなったよ。","ENG":"Having to listen to such complaints intermixed with compassion after a long time made me very uncomfortable.","TWN":"好久沒聽到充滿憐憫的抱怨，真是有點尷尬。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이제 나와도 돼, 중사. 소리쳐서 미안해.","JPN":"もう出てきていいよ、軍曹。大声出してごめんね。","ENG":"You can come out now, Sergeant. I’m sorry for shouting at you.","TWN":"你可以出來了，中士。剛不好意思，對你大吼。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어머니는…… 좀 진정되셨나요?","JPN":"お母さんは……ちょっとは落ち着きました？","ENG":"Has your mother...calmed down?","TWN":"你媽媽……冷靜下來了嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"진이 빠져서 쉬고 계셔. 한창이셨던 시절처럼 발버둥을 치시니 지칠 만도 하지.","JPN":"くたくたになって寝てる。元気だった頃のように暴れたから疲れたはずだよ。","ENG":"She’s resting now. She’s extremely tired. It’s understandable, she was thrashing about so hard.","TWN":"鬧到累了，現在在休息，剛才那麼用力掙扎，怎麼可能不累。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……오해가 생길까 봐 미리 말씀드리는데, 구경거리라고 생각하진 않았어요.","JPN":"……誤解のないように言っておきますが、見せ物だとは思いませんでした。","ENG":"Good... In case you misunderstand, I never thought of it as entertainment.","TWN":"……我話先說在前頭，我沒有要看熱鬧的意思，你不要誤會。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"알아. 그럴 사람 아니라는 거.","JPN":"わかってるよ。そんな人じゃないってこと。","ENG":"I know. I know you’re not that kind of person.","TWN":"我知道你不是那種人。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런 낯뜨거운 멘트 하지 말라니까요. 저랑 알고 지낸 지 얼마나 됐다고.","JPN":"そんな恥ずかしいこと言わないでくださいってば。長い付き合いでもないんですから。","ENG":"There’s no need for that. We’ve known each other only for a short time.","TWN":"你可以不要說那種會令人害羞的話嗎？我們明明就沒有認識很久！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"2종 침식체가 나타났을 때 혼자 도망치지 않았잖아?","JPN":"第2種侵食体が現れた時、一人で逃げなかったでしょ？","ENG":"When that Category 2 C.O. appeared, you had the chance to run away, but you didn’t.","TWN":"2類侵蝕體出現的時候，你沒有扔下我自己逃走不是嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"내가 시선을 끄는 동안 기회는 몇 번이나 있었어.","JPN":"私が注意を引いてる間に何度も逃げるチャンスはあったのに。","ENG":"You had plenty of opportunities to while I was distracting it.","TWN":"你明明有很多機會可以逃。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……하아. 그거야 당연하죠.","JPN":"……はあ。当たり前じゃないですか。","ENG":"...Hah. Of course I wouldn’t run away.","TWN":"……哈，這是當然的。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그 자리에서 내뺐다간 보안국에 찍혀서 평생 도망자 인생 확정이잖아요.","JPN":"その場で逃げ出したら保安局に目を付けられて、一生逃亡者人生確定です。","ENG":"If I ran away then, I’d have to live the rest of my life as a fugitive with the Department of National Security after me.","TWN":"要是我當時逃走的話，我會一輩子被安全局冠上逃亡者的標籤吧？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그리고 이 무공훈장이란 거, 생각보다 무겁다고요.","JPN":"それにこの勲章って以外と重いんですよ。","ENG":"Also, the weight of responsibility having received the Medal of Honor is heavier than you thought.","TWN":"而且這個勳章，可是比想像中還沈重呢。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"후후. 그 나이에는 무거울 만도 하지. 애초에 살아서 수훈된 경우는 네가 처음이야.","JPN":"ふふ。その年には重いはずだよね。そもそも生きたまま受勲した人はあなたが初めてよ。","ENG":"Fuu fuu. It should be at your age. You’re the first person to receive that medal while alive after all.","TWN":"呵呵，以你的年紀而言，或許是有點沈重。畢竟你是第一個活著授勳的。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"잠기운은 다 달아난 모양인데, 안젤라랑 셋이서 술 한 잔 할까?","JPN":"眠気が覚めちゃったみたいだけど、アンジェラと三人で一杯やる？","ENG":"I don’t think I’m going to be able to get any sleep tonight so, do you want to grab a drink with Angela?","TWN":"我看你現在應該沒什麼睡意吧？要不要找安潔拉一起，我們三個喝一杯怎麼樣？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사양할게요. 제 신조 중 하나가 <color=#ffd34c>술, 담배, 도박은 절대 하지 말자</color> 라서.","JPN":"遠慮します。私のモットーは<color=#ffd34c>酒、タバコ、賭けには絶対手を出さない</color>、なんで。","ENG":"I’ll pass. I’ve vowed to <color=#ffd34c>never drink, smoke, or gamble</color>.","TWN":"請恕我拒絕，我有三不堅持，<color=#ffd34c>不菸、不酒、不賭</color>。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"혹시 수도원에서 자랐어?","JPN":"もしかして修道院育ち？","ENG":"...Were you raised in a monastery or something?","TWN":"你是在修道院長大的嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어릴 적부터 부모님이 할아버지가 그걸로 집안 말아먹는 바람에 망명할 돈도 없었다고 투덜거렸거든요.","JPN":"小さい頃から両親が、「お爺さんがそれで食いつぶしたせいで亡命する金もなかった」ってブツブツ言ってましたから。","ENG":"Ever since I was young, my parents complained that my grandpa had no money to flee the country because he drank and gambled it all away.","TWN":"我從小就聽我爸媽在唸，說我爺爺因為那些東西而散盡家產，連跑路的錢都沒有。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래서 그 양반에게 뭐 한 푼 보태 준 적 있기나 한지는 모르겠지만요.","JPN":"だからって、お爺さんにお金あげたことがあるのかは知りませんけど。","ENG":"I’m not sure if we ever helped him with anything ever.","TWN":"不過我也不知道他們是否給過他一毛錢。"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그러면 우유라도 마실래? 암시장에서 사 온 거라 탈날 걱정은…….","JPN":"それじゃあ、牛乳でも飲む？　闇市場で買ってきたからお腹をこわす心配は……","ENG":"Then how about a glass of milk? I got it from the black market so there’s no need to worry about...","TWN":"那還是你要喝牛奶嗎？是從黑市買回來的，不保證沒問題……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사, 들려?","JPN":"軍曹、聞いた？","ENG":"Sergeant, did you hear that?","TWN":"中士，你有聽到嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네, 여러 명의 발소리. 철컥거리는 건 총기가 장구류에 부딪치면서 나는 소리 같아요.","JPN":"はい、数人の足の音。 ガチャガチャいってるのは銃が装具とぶつかる音でしょう。","ENG":"Yeah, that’s a lot of footsteps. I can hear guns clanking, too.","TWN":"有，好幾個人的腳步聲，還有像是槍械碰撞到個裝攜行袋的聲音。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"건물 주위를 에워싸고 있어요. 보안국일까요?","JPN":"建物を包囲してますね。保安局でしょうか？","ENG":"They’re surrounding the building. Could it be the National Security?","TWN":"他們包圍在房屋周圍，是安全局的人嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"보안국 사람들이면 벌써 현관문을 걷어차고 들어왔어.","JPN":"保安局だったらもうすでに玄関壊して入ってきてるよ。","ENG":"If it was the National Security, they’d have already kicked down the front door by now.","TWN":"要是安全局的人，應該早就破門而入。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……어쩌면, 클림트의 실종에 관계된 자들일지도 몰라.","JPN":"……もしかしたら、クリムトの失踪と関係があるかも知れない。","ENG":"...Maybe it’s the people connected to Klimt’s disappearance.","TWN":"……說不定是和克里姆失蹤有關的人？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 저쪽이 본격적으로 행동하기 전에 보안국에 연락해야죠!","JPN":"それじゃあ、あっちが本格的に行動に出る前に保安局に連絡しないと！","ENG":"Then we need to call the National Security before they act!","TWN":"那在他們展開行動前，應該先趕快聯絡安全局吧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으아씨! 행동이 쓸데없이 빠르잖아?!","JPN":"うあぁ！　行動が早すぎるっての！！","ENG":"Damn! There’s no time!","TWN":"該死！動作真快！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사! 고개 숙여, 수류탄이야!","JPN":"軍曹！　頭を下げて、手榴弾よ！","ENG":"Sergeant! Get down, it’s a grenade!","TWN":"中士！低頭！是手榴彈！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"콜록……! 콜록!","JPN":"ゲホ……！　ゲホ！","ENG":"*Cough...!* *Cough!*","TWN":"咳咳……！咳咳！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아! 콜록……! 갑자기 이게 무슨 난리야……?","JPN":"レア！　ゲホッ……！　いきなり何なの……？","ENG":"Leah! *Cough...!* What’s going on...?","TWN":"蕾亞！咳咳……！這是怎麼回事……？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"설명할 시간 없어!","JPN":"説明してる暇はないよ！","ENG":"There’s no time to explain!","TWN":"現在沒時間跟你解釋！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사! 저 녀석들은 내가 상대할게! 엄마랑 안젤라를 안전한 곳으로 데려가 줘!","JPN":"軍曹！　あいつらは私がなんとかする！　お母さんとアンジェラを安全な場所まで連れてって！","ENG":"Sergeant! I’ll take care of these guys. Get Mom and Angela somewhere safe!","TWN":"中士！那些傢伙交給我！你帶我媽和安潔拉到安全的地方去！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안전한 곳이 어딘데요?! 수도 한복판에서 공격 받은 마당에!","JPN":"安全な場所ってどこですか！？　首都のど真ん中で攻撃されたのに！","ENG":"Where is somewhere safe?! We’re being attacked even in the middle of the capital!","TWN":"安全的地方是哪裡？！我們現在是在市中心遭到攻擊欸！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"보안국으로 가!","JPN":"保安局に行って！","ENG":"Get to the National Security!","TWN":"去安全局！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"저기 뛰쳐 나온 여자다! 죽여 버려!!","JPN":"あの飛び出した女だ！　殺せ！！","ENG":"That’s her!! The girl that just ran out! Kill her!","TWN":"就是那個衝出來的女人！殺無赦！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지, 진짜 가 버렸어…….","JPN":"ほ、本当に行っちゃった……","ENG":"Sh-She really just ran out...","TWN":"她…就這樣衝出去啦……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"중사님, 우리는 어쩌지?","JPN":"軍曹さん、私たちはどうすればいいの？","ENG":"Sergeant, what should we do?","TWN":"中士，我們怎麼辦？"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"후으으…….","JPN":"ふうぅ……","ENG":"Uhhhh...","TWN":"哀哀……"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이, 이이, 일단 어머니부터 모시고 밖으로 나가죠! 여기 계속 있으면 위험해요!","JPN":"と、とと、とりあえずお母さんを連れて外へ出ましょう！　ここに残ってたら危険です！","ENG":"F-First, let’s get Leah’s mother outside! It’s too dangerous to stay here!","TWN":"那個…就…總之…先帶伯母離開吧！繼續待在這裡會有危險！"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};